() => {
  const titleEl = document.querySelector('.titleline a') || document.querySelector('title');
  const storyTitle = titleEl ? titleEl.textContent.trim() : '';

  const scoreEl = document.querySelector('.score');
  const pointsMatch = scoreEl ? scoreEl.textContent.match(/(\d+)\s+points?/) : null;
  const points = pointsMatch ? pointsMatch[1] : '';

  let totalComments = '';
  const subline = document.querySelector('.subtext') || document.querySelector('td.subtext');
  if (subline) {
    const links = Array.from(subline.querySelectorAll('a'));
    const commentsLink = links.reverse().find(a => /\bcomment(s)?\b|\bdiscuss\b/i.test((a.textContent || '').trim()));
    if (commentsLink) {
      const t = (commentsLink.textContent || '').trim();
      const m = t.match(/(\d+)\s+comment/i);
      totalComments = m ? m[1] : (t.toLowerCase() === 'discuss' ? '0' : '');
    }
  }

  const rows = Array.from(document.querySelectorAll('tr.athing.comtr'));
  const nodes = [];
  const stack = [];

  for (const row of rows) {
    const userEl = row.querySelector('.hnuser');
    if (!userEl) continue;
    const user = userEl.textContent.trim();
    const indImg = row.querySelector('td.ind img');
    const level = indImg ? parseInt(indImg.getAttribute('width') || '0', 10) : 0;

    const node = { user, level, directReplies: 0, parent: -1 };
    while (stack.length && stack[stack.length - 1].level >= level) stack.pop();
    if (stack.length) {
      node.parent = stack[stack.length - 1].idx;
      nodes[stack[stack.length - 1].idx].directReplies += 1;
    }
    const idx = nodes.length;
    nodes.push(node);
    stack.push({ level, idx });
  }

  const topLevel = nodes.filter(n => n.parent === -1);
  let topCommentAuthor = '';
  if (topLevel.length) {
    topLevel.sort((a, b) => b.directReplies - a.directReplies);
    topCommentAuthor = topLevel[0].user;
  }

  return { storyTitle, points, totalComments, topCommentAuthor, topLevelSample: topLevel.slice(0, 5) };
}

